+---
+interface Props {
+  currentPage: number;
+  totalPages: number;
+  basePath: string;
+}
+
+const { currentPage, totalPages, basePath } = Astro.props;
+
+function getPageUrl(page: number): string {
+  return page === 1 ? basePath : `${basePath}/${page}`;
+}
+---
+
+{totalPages > 1 && (
+  <nav class="flex items-center justify-center gap-2 mt-8">
+    {currentPage > 1 ? (
+      <a href={getPageUrl(currentPage - 1)} class="font-mono text-sm px-3 py-1.5 border border-border rounded-md text-text-muted hover:text-text hover:border-text-dim transition-colors">
+        &larr;
+      </a>
+    ) : (
+      <span class="font-mono text-sm px-3 py-1.5 border border-border-subtle rounded-md text-text-dim cursor-not-allowed">
+        &larr;
+      </span>
+    )}
+    <span class="font-mono text-sm text-text-dim">
+      {currentPage} / {totalPages}
+    </span>
+    {currentPage < totalPages ? (
+      <a href={getPageUrl(currentPage + 1)} class="font-mono text-sm px-3 py-1.5 border border-border rounded-md text-text-muted hover:text-text hover:border-text-dim transition-colors">
+        &rarr;
+      </a>
+    ) : (
+      <span class="font-mono text-sm px-3 py-1.5 border border-border-subtle rounded-md text-text-dim cursor-not-allowed">
+        &rarr;
+      </span>
+    )}
+  </nav>
+)}

