@@ -0,0 +1,46 @@
+---
+import Page from '@/layouts/Page.astro';
+import PostCard from '@/components/PostCard.astro';
+import { getCollection } from 'astro:content';
+
+export async function getStaticPaths() {
+  const allPosts = await getCollection('blog', ({ data }) => !data.draft);
+  const tags = [...new Set(allPosts.flatMap((post) => post.data.tags))];
+
+  return tags.map((tag) => ({
+    params: { tag },
+    props: {
+      tag,
+      posts: allPosts
+        .filter((post) => post.data.tags.includes(tag))
+        .sort((a, b) => b.data.pubDate.valueOf() - a.data.pubDate.valueOf()),
+    },
+  }));
+}
+
+const { tag, posts } = Astro.props;
+---
+
+<Page title={`Posts tagged "${tag}"`} description={`Blog posts about ${tag} by Marcel Heidebrecht`}>
+  <div class="mb-8">
+    <a href="/blog" class="font-mono text-sm text-text-muted hover:text-accent transition-colors">
+      &larr; all posts
+    </a>
+  </div>
+  <h1 class="text-3xl font-bold tracking-tight mb-2">
+    <span class="text-accent">#</span>{tag}
+  </h1>
+  <p class="font-mono text-sm text-text-dim mb-8">{posts.length} post{posts.length !== 1 ? 's' : ''}</p>
+
+  <div class="flex flex-col gap-3">
+    {posts.map((post: any) => (
+      <PostCard
+        title={post.data.title}
+        description={post.data.description}
+        pubDate={post.data.pubDate}
+        tags={post.data.tags}
+        slug={post.id}
+      />
+    ))}
+  </div>
+</Page>

