---
interface Props {
  tags: string[];
  activeTag?: string;
  linked?: boolean;
}

const { tags, activeTag, linked = true } = Astro.props;
---

<div class="flex flex-wrap gap-1.5">
  {tags.map((tag) => (
    linked ? (
      <a
        href={`/blog/tags/${tag}`}
        class:list={['tag', activeTag === tag && '!text-accent !border-accent']}
      >
        {tag}
      </a>
    ) : (
      <span class="tag">{tag}</span>
    )
  ))}
</div>

---
interface Props {
  prev?: { slug: string; title: string } | null;
  next?: { slug: string; title: string } | null;
}

const { prev, next } = Astro.props;
---

{((prev || next)) && (
  <nav class="flex items-center justify-between gap-4 mt-12 pt-6 border-t border-border">
    {prev ? (
      <a href={`/blog/${prev.slug}`} class="font-mono text-sm text-text-muted hover:text-accent transition-colors truncate">
        &larr; {prev.title}
      </a>
    ) : <span />}
    {next ? (
      <a href={`/blog/${next.slug}`} class="font-mono text-sm text-text-muted hover:text-accent transition-colors truncate text-right">
        {next.title} &rarr;
      </a>
    ) : <span />}
  </nav>
)}

---
interface Props {
  currentPage: number;
  totalPages: number;
  basePath: string;
}

const { currentPage, totalPages, basePath } = Astro.props;

function getPageUrl(page: number): string {
  return page === 1 ? basePath : `${basePath}/${page}`;
}
---

{totalPages > 1 && (
  <nav class="flex items-center justify-center gap-2 mt-8">
    {currentPage > 1 ? (
      <a href={getPageUrl(currentPage - 1)} class="font-mono text-sm px-3 py-1.5 border border-border rounded-md text-text-muted hover:text-text hover:border-text-dim transition-colors">
        &larr;
      </a>
    ) : (
      <span class="font-mono text-sm px-3 py-1.5 border border-border-subtle rounded-md text-text-dim cursor-not-allowed">
        &larr;
      </span>
    )}
    <span class="font-mono text-sm text-text-dim">
      {currentPage} / {totalPages}
    </span>
    {currentPage < totalPages ? (
      <a href={getPageUrl(currentPage + 1)} class="font-mono text-sm px-3 py-1.5 border border-border rounded-md text-text-muted hover:text-text hover:border-text-dim transition-colors">
        &rarr;
      </a>
    ) : (
      <span class="font-mono text-sm px-3 py-1.5 border border-border-subtle rounded-md text-text-dim cursor-not-allowed">
        &rarr;
      </span>
    )}
  </nav>
)}

