---
import Base from '@/layouts/Base.astro';
import Hero from '@/components/Hero.astro';
import PostCard from '@/components/PostCard.astro';
import ProjectCard from '@/components/ProjectCard.astro';
import { getCollection } from 'astro:content';

const allPosts = (await getCollection('blog', ({ data }) => !data.draft))
  .sort((a, b) => b.data.pubDate.valueOf() - a.data.pubDate.valueOf())
  .slice(0, 3);

const featuredProjects = (await getCollection('projects'))
  .filter((p) => p.data.featured)
  .sort((a, b) => b.data.sortOrder - a.data.sortOrder)
  .slice(0, 3);
---

<Base title="Home">
  <Hero />

  {allPosts.length > 0 && (
    <section class="mb-16">
      <div class="section-heading">
        <h2 class="font-mono text-sm font-medium text-text-muted">recent posts</h2>
      </div>
      <div class="flex flex-col gap-3">
        {allPosts.map((post) => (
          <PostCard
            title={post.data.title}
            description={post.data.description}
            pubDate={post.data.pubDate}
            tags={post.data.tags}
            slug={post.id}
          />
        ))}
      </div>
      <a href="/blog" class="inline-block mt-4 font-mono text-sm text-text-dim hover:text-accent transition-colors">
        all posts &rarr;
      </a>
    </section>
  )}

  {featuredProjects.length > 0 && (
    <section>
      <div class="section-heading">
        <h2 class="font-mono text-sm font-medium text-text-muted">featured projects</h2>
      </div>
      <div class="grid gap-3 sm:grid-cols-2">
        {featuredProjects.map((project) => (
          <ProjectCard
            title={project.data.title}
            description={project.data.description}
            tags={project.data.tags}
            url={project.data.url}
            repo={project.data.repo}
          />
        ))}
      </div>
      <a href="/projects" class="inline-block mt-4 font-mono text-sm text-text-dim hover:text-accent transition-colors">
        all projects &rarr;
      </a>
    </section>
  )}
</Base>

---
import Page from '@/layouts/Page.astro';
import PostCard from '@/components/PostCard.astro';
import TagList from '@/components/TagList.astro';
import PaginationNav from '@/components/PaginationNav.astro';
import { getCollection } from 'astro:content';

export async function getStaticPaths({ paginate }: any) {
  const allPosts = (await getCollection('blog', ({ data }) => !data.draft))
    .sort((a, b) => b.data.pubDate.valueOf() - a.data.pubDate.valueOf());
  return paginate(allPosts, { pageSize: 10 });
}

const { page } = Astro.props;

const allTags = [...new Set(page.data.flatMap((post: any) => post.data.tags))].sort();
---

<Page title="Blog" description="Engineering articles by Marcel Heidebrecht">
  <h1 class="text-3xl sm:text-4xl font-bold tracking-tight mb-2">Blog</h1>
  <p class="font-mono text-sm text-text-dim mb-6">thoughts on engineering, infrastructure &amp; code</p>

  {allTags.length > 0 && (
    <div class="mb-8">
      <TagList tags={allTags} linked={true} />
    </div>
  )}

  <div class="flex flex-col gap-3">
    {page.data.map((post: any) => (
      <PostCard
        title={post.data.title}
        description={post.data.description}
        pubDate={post.data.pubDate}
        tags={post.data.tags}
        slug={post.id}
      />
    ))}
  </div>

  <PaginationNav currentPage={page.currentPage} totalPages={page.lastPage} basePath="/blog" />
</Page>

---
import Page from '@/layouts/Page.astro';
import PostCard from '@/components/PostCard.astro';
import { getCollection } from 'astro:content';

export async function getStaticPaths() {
  const allPosts = await getCollection('blog', ({ data }) => !data.draft);
  const tags = [...new Set(allPosts.flatMap((post) => post.data.tags))];

  return tags.map((tag) => ({
    params: { tag },
    props: {
      tag,
      posts: allPosts
        .filter((post) => post.data.tags.includes(tag))
        .sort((a, b) => b.data.pubDate.valueOf() - a.data.pubDate.valueOf()),
    },
  }));
}

const { tag, posts } = Astro.props;
---

<Page title={`Posts tagged "${tag}"`} description={`Blog posts about ${tag} by Marcel Heidebrecht`}>
  <div class="mb-8">
    <a href="/blog" class="font-mono text-sm text-text-muted hover:text-accent transition-colors">
      &larr; all posts
    </a>
  </div>
  <h1 class="text-3xl font-bold tracking-tight mb-2">
    <span class="text-accent">#</span>{tag}
  </h1>
  <p class="font-mono text-sm text-text-dim mb-8">{posts.length} post{posts.length !== 1 ? 's' : ''}</p>

  <div class="flex flex-col gap-3">
    {posts.map((post: any) => (
      <PostCard
        title={post.data.title}
        description={post.data.description}
        pubDate={post.data.pubDate}
        tags={post.data.tags}
        slug={post.id}
      />
    ))}
  </div>
</Page>

